import './Preview.scss';

import { Modal } from ':components/Modal';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import React, { useEffect, useState } from 'react';

import { Fullscreen } from './components/Fullscreen/Fullscreen';
import { Header } from './components/Header/Header';
import { ImageGallery } from './components/ImageGallery/ImageGallery';
import { ImagePreview } from './components/ImagePreview/ImagePreview';
import { Navigation } from './components/Navigation/Navigation';
import { PDFGallery } from './components/PDFGallery/PDFGallery';
import { PDFPreview } from './components/PDFPreview/PDFPreview';
import { Rotation } from './components/Rotation/Rotation';
import { WordGallery } from './components/WordGallery/WordGallery';
import { WordPreview } from './components/WordPreview/WordPreview';
import { Zoom } from './components/Zoom/Zoom';
import type { ImageGalleryProps, PreviewProps } from './Preview.types';

export const Preview: React.FC<PreviewProps> = ({
	value,
	type,
	modal = false,
	className,
	onExpand,
	dataTestId = 'Preview',
	applicationRootId = 'root',
	enableRotation = true,
	enableZoom = true,
	headerCustomElements,
	onClose,
	navigation,
	gallery,
	description,
}) => {
	const ZOOM_STEP_RATIO = 0.25;
	const ZOOM_MIN_RATIO = 0.5;
	const ZOOM_MAX_RATIO = 4;

	const [scaleState, setScaleState] = useState({
		current: 1,
		initial: 1,
	});
	const [rotation, setRotation] = useState(0);
	const [activePDFPage, setActivePDFPage] = useState(0);
	const [activeWordPage, setActiveWordPage] = useState(0);

	const zoomStep = scaleState.initial * ZOOM_STEP_RATIO;
	const zoomMin = scaleState.initial * ZOOM_MIN_RATIO;
	const zoomMax = scaleState.initial * ZOOM_MAX_RATIO;

	const handleZoomIn = () => {
		setScaleState(prev => ({
			...prev,
			current: Math.min(zoomMax, prev.current + zoomStep),
		}));
	};

	const handleZoomOut = () => {
		setScaleState(prev => ({
			...prev,
			current: Math.max(zoomMin, prev.current - zoomStep),
		}));
	};

	const handleInitialScale = (initialScale: number) => {
		setScaleState(prev => ({
			...prev,
			initial: initialScale,
			current: prev.current === prev.initial ? initialScale : prev.current,
		}));
	};

	const handleRotateLeft = () => {
		setRotation(prevRotation => (prevRotation - 90) % 360);
	};

	const handleRotateRight = () => {
		setRotation(prevRotation => (prevRotation + 90) % 360);
	};

	useEffect(() => {
		setRotation(0);
		setActivePDFPage(0);
		setActiveWordPage(0);
		setScaleState({
			current: 1,
			initial: 1,
		});
	}, [value]);

	const component = (
		<div data-testid={dataTestId} className={classNames('dsb_preview', modal && 'dsb_preview-modal', className)}>
			<Header type={type} value={value} onClose={onClose} modal={modal} headerCustomElements={headerCustomElements} />
			<div className="dsb_preview__body">
				<div className={classNames('dsb_preview__content', gallery && `dsb_preview__content-${type}-gallery`)}>
					{type === 'pdf' ? (
						<PDFPreview
							activePage={activePDFPage}
							rotation={rotation}
							scale={scaleState.current}
							value={value}
							onInitialScale={handleInitialScale}
						/>
					) : type === 'docx' ? (
						<WordPreview
							scale={scaleState.current}
							value={value}
							onInitialScale={handleInitialScale}
							activePage={activeWordPage}
						/>
					) : (
						type === 'img' &&
						'alt' in value && (
							<ImagePreview
								rotation={rotation}
								scale={scaleState.current}
								value={value}
								onInitialScale={handleInitialScale}
							/>
						)
					)}
				</div>
				{gallery && type === 'pdf' && (
					<PDFGallery selectedIndex={activePDFPage} onClick={index => setActivePDFPage(index)} value={value} />
				)}
				{gallery && type === 'docx' && (
					<WordGallery selectedIndex={activeWordPage} onClick={index => setActiveWordPage(index)} value={value} />
				)}
			</div>
			<div className="dsb_preview__controls">
				{!modal && onExpand && <Fullscreen onClick={onExpand} />}
				{enableZoom && (
					<Zoom
						onZoomIn={handleZoomIn}
						onZoomOut={handleZoomOut}
						onZoomReset={() =>
							setScaleState(prev => ({
								...prev,
								current: prev.initial,
							}))
						}
					/>
				)}
				{enableRotation && type !== 'docx' && (
					<Rotation onRotateLeft={handleRotateLeft} onRotateRight={handleRotateRight} />
				)}
			</div>
			<div
				className={classNames(
					'dsb_preview__explorer',
					gallery && !modal && type === 'img' && 'dsb_preview__explorer-gallery',
				)}
			>
				{navigation && (
					<Navigation
						onClickNext={navigation.onClickNext}
						onClickPrev={navigation.onClickPrev}
						max={navigation.max}
						value={navigation.value}
					/>
				)}
				{!modal && <Typography variant="body2">{description}</Typography>}
				{gallery && type === 'img' && <ImageGallery {...(gallery as ImageGalleryProps)} />}
				{/* {navigation && !(!modal && gallery) && ( */}
			</div>
		</div>
	);

	return modal ? (
		<Modal applicationRootElement={applicationRootId} open={true}>
			{component}
		</Modal>
	) : (
		component
	);
};
